// src/pages/ResultsPage.js
import React, { useEffect, useRef, useState } from "react";
import { saveSession } from "../utils/firebase";
import "./ResultsPage.css";

// ── Highlighted transcript ────────────────────────────────────────────────────
function HighlightedTranscript({ transcript, fillerBreakdown, lowConfidenceWords }) {
  if (!transcript) return <span>No transcript available.</span>;
  const fillerSet = new Set((fillerBreakdown || []).map(f => f.word.toLowerCase()));
  const lowConfSet = new Set((lowConfidenceWords || []).map(w => w.word.toLowerCase()));
  const tokens = transcript.split(/(\s+)/);
  return (
    <span>
      {tokens.map((token, i) => {
        const clean = token.toLowerCase().replace(/[^a-z]/g, "").trim();
        if (!clean) return <span key={i}>{token}</span>;
        if (fillerSet.has(clean))
          return <mark key={i} className="highlight-filler" title="Filler word">{token}</mark>;
        if (lowConfSet.has(clean))
          return <mark key={i} className="highlight-pronunciation" title="Unclear pronunciation">{token}</mark>;
        return <span key={i}>{token}</span>;
      })}
    </span>
  );
}

// ── Formatted 4-section feedback ─────────────────────────────────────────────
function FormattedFeedback({ feedback }) {
  if (!feedback) return <p style={{ color: "var(--text-muted)" }}>No feedback available.</p>;
  const lines = feedback.split("\n").filter(Boolean);
  return (
    <div className="feedback-sections">
      {lines.map((line, i) => {
        const isHeader = line.startsWith("**") && line.endsWith("**");
        if (isHeader) return <p key={i} className="feedback-section-header">{line.replace(/\*\*/g, "")}</p>;
        const parts = line.split(/(\*\*[^*]+\*\*)/g);
        return (
          <p key={i} className="feedback-para">
            {parts.map((p, j) => p.startsWith("**") && p.endsWith("**")
              ? <strong key={j}>{p.replace(/\*\*/g, "")}</strong>
              : p)}
          </p>
        );
      })}
    </div>
  );
}

// ── Score ring ────────────────────────────────────────────────────────────────
function ScoreRing({ score }) {
  const s = Number(score) || 0;
  const r = 54, circ = 2 * Math.PI * r;
  const offset = circ - (s / 100) * circ;
  const color = s >= 80 ? "#4ecca3" : s >= 65 ? "#ffd166" : "#fc6c8f";
  const label = s >= 80 ? "Excellent" : s >= 65 ? "Good" : s >= 50 ? "Fair" : "Needs Work";
  return (
    <div className="score-ring-wrap">
      <div className="score-ring">
        <svg viewBox="0 0 120 120" width="120" height="120">
          <circle className="score-ring-bg" cx="60" cy="60" r={r} />
          <circle className="score-ring-fill" cx="60" cy="60" r={r}
            strokeDasharray={circ} strokeDashoffset={offset} stroke={color} />
        </svg>
        <div className="score-ring-text">
          <span className="score-num" style={{ color }}>{s}</span>
          <span className="score-label">/ 100</span>
        </div>
      </div>
      <span className="tag" style={{ background: `${color}22`, color }}>{label}</span>
    </div>
  );
}

// ── Small score bar ───────────────────────────────────────────────────────────
function ScoreBar({ label, value }) {
  const v = Number(value) || 0;
  const color = v >= 80 ? "#4ecca3" : v >= 60 ? "#ffd166" : "#fc6c8f";
  return (
    <div className="score-bar-item">
      <div className="score-bar-top">
        <span className="score-bar-label">{label}</span>
        <span className="score-bar-value" style={{ color }}>{v}</span>
      </div>
      <div className="score-bar-track">
        <div className="score-bar-fill" style={{ width: `${v}%`, background: color }} />
      </div>
    </div>
  );
}

// ── Metric card ───────────────────────────────────────────────────────────────
function MetricCard({ label, value, unit, note, color = "#7c6cfc" }) {
  return (
    <div className="metric-card card">
      <span className="metric-value" style={{ color }}>{value ?? "—"}</span>
      <span className="metric-unit">{unit}</span>
      <span className="metric-label">{label}</span>
      {note && <span className="metric-note">{note}</span>}
    </div>
  );
}

// ── Pronunciation coach ───────────────────────────────────────────────────────
function PronunciationCoach({ pronunciationTips, lowConfidenceWords, avgConfidence }) {
  const [expanded, setExpanded] = useState(null);
  const hasTips  = pronunciationTips && pronunciationTips.length > 0;
  const hasFlags = lowConfidenceWords && lowConfidenceWords.length > 0;
  const clarity  = Number(avgConfidence) || 95;
  const getColor = (prob) => prob >= 75 ? "#ffd166" : prob >= 50 ? "#fc8c4a" : "#fc6c8f";

  return (
    <div className="card pronunciation-card">
      <div className="feedback-header">
        <span className="feedback-icon">🗣️</span>
        <div>
          <h3>Pronunciation Coach</h3>
          <p className="feedback-sub">Analyzed from your actual speech · Clarity: {clarity}%</p>
        </div>
      </div>

      {hasFlags ? (
        <div className="mispronounced-section">
          <p className="mispronounced-intro">
            Words that were <strong>unclear in your recording</strong> — lower % = harder to understand:
          </p>
          <div className="mispronounced-grid">
            {lowConfidenceWords.map((w, i) => (
              <div key={i} className="mispronounced-chip" style={{ borderColor: getColor(w.prob) }}>
                <span className="mis-word">"{w.word}"</span>
                <span className="mis-prob" style={{ color: getColor(w.prob) }}>{w.prob}%</span>
                <span className="mis-label" style={{ color: getColor(w.prob) }}>
                  {w.prob >= 75 ? "Slight issue" : w.prob >= 50 ? "Unclear" : "Hard to hear"}
                </span>
              </div>
            ))}
          </div>
        </div>
      ) : (
        <div className="pronunciation-clean">
          <span className="clean-icon">✅</span>
          <p>No significant clarity issues detected. Your words came through clearly!</p>
        </div>
      )}

      {hasTips && (
        <div className="pron-tips-section">
          <p className="tips-label">💬 Specific corrections based on what you said:</p>
          <div className="pron-tips-list">
            {pronunciationTips.map((tip, i) => (
              <div
                key={i}
                className={`pron-tip-card ${expanded === i ? "expanded" : ""}`}
                onClick={() => setExpanded(expanded === i ? null : i)}
              >
                <div className="pron-tip-header">
                  <div className="pron-tip-left">
                    <span className="pron-tip-word">"{tip.word}"</span>
                    <span className="pron-tip-issue">{tip.issue}</span>
                  </div>
                  <span className="pron-tip-toggle">{expanded === i ? "▲" : "▼"}</span>
                </div>
                {expanded === i && (
                  <div className="pron-tip-body">
                    {tip.correct && (
                      <div className="pron-detail">
                        <span className="pron-detail-label">✅ Correct pronunciation</span>
                        <span className="pron-detail-value correct">{tip.correct}</span>
                      </div>
                    )}
                    {tip.tip && (
                      <div className="pron-detail">
                        <span className="pron-detail-label">💡 Quick fix</span>
                        <span className="pron-detail-value">{tip.tip}</span>
                      </div>
                    )}
                    {tip.example && (
                      <div className="pron-detail">
                        <span className="pron-detail-label">📖 Example</span>
                        <span className="pron-detail-value example">"{tip.example}"</span>
                      </div>
                    )}
                    {tip.word !== "Great job" && (
                      <a
                        href={`https://youglish.com/pronounce/${encodeURIComponent(tip.word)}/english`}
                        target="_blank"
                        rel="noreferrer"
                        className="youglish-link"
                        onClick={e => e.stopPropagation()}
                      >
                        🔊 Hear it on YouGlish →
                      </a>
                    )}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      {!hasTips && (
        <p className="pron-no-tips">Keep practicing — your pronunciation was good overall!</p>
      )}
    </div>
  );
}

// ── Debug helper (only shows in development) ──────────────────────────────────
function DebugPanel({ results }) {
  const [show, setShow] = useState(false);
  if (process.env.NODE_ENV !== "development") return null;
  return (
    <div style={{ margin: "16px 0" }}>
      <button onClick={() => setShow(!show)} style={{ fontSize: 12, opacity: 0.5, background: "none", border: "1px solid #333", color: "#888", padding: "4px 10px", cursor: "pointer", borderRadius: 4 }}>
        {show ? "Hide" : "Show"} raw data (dev only)
      </button>
      {show && (
        <pre style={{ fontSize: 11, background: "#111", padding: 12, borderRadius: 8, overflow: "auto", color: "#aaa", marginTop: 8 }}>
          {JSON.stringify(results, null, 2)}
        </pre>
      )}
    </div>
  );
}

// ── Main Results Page ─────────────────────────────────────────────────────────
export default function ResultsPage({ navigate, results }) {
  const saved = useRef(false);

  // Safely destructure with full fallbacks
  const transcript       = results?.transcript       || "";
  const metrics          = results?.metrics          || {};
  const fillers          = results?.fillers          || { total: 0, breakdown: [], ratio: 0 };
  const repetition       = results?.repetition       || [];
  const scores           = results?.scores           || {};
  const feedback         = results?.feedback         || "";
  const pronunciationTips = results?.pronunciationTips || [];
  const avgConfidence    = results?.avgConfidence    ?? 95;
  const lowConfidenceWords = results?.lowConfidenceWords || [];
  const scenario         = results?.scenario         || "General Speaking";

  useEffect(() => {
    if (!saved.current && transcript) {
      saved.current = true;
      saveSession({ scenario, transcript, metrics, fillers, scores, feedback, date: new Date().toISOString() });
    }
  }, []);

  // Show error if truly nothing came back
  if (!results) {
    return (
      <div className="results-page center">
        <div style={{ textAlign: "center" }}>
          <p style={{ color: "var(--text-muted)", marginBottom: 16 }}>No results found. Please try recording again.</p>
          <button className="btn btn-primary" onClick={() => navigate("practice")}>🎙️ Try Again</button>
        </div>
      </div>
    );
  }

  // Show a helpful message if transcript is missing but results exist
  if (!transcript) {
    return (
      <div className="results-page center">
        <div style={{ textAlign: "center" }}>
          <p style={{ color: "var(--text-muted)", marginBottom: 8 }}>⚠️ Transcript was empty — no speech was detected.</p>
          <p style={{ color: "var(--text-muted)", fontSize: 14, marginBottom: 16 }}>Try speaking louder or closer to your microphone.</p>
          <button className="btn btn-primary" onClick={() => navigate("practice")}>🎙️ Try Again</button>
          <DebugPanel results={results} />
        </div>
      </div>
    );
  }

  // Derived display values — all safe with fallbacks
  const overall      = Number(scores?.overall)   || 0;
  const wpm          = Number(metrics?.wpm)       || 0;
  const wordCount    = Number(metrics?.wordCount) || 0;
  const pace         = metrics?.pace              || "Unknown";
  const totalFillers = Number(fillers?.total)     || 0;
  const fillerRatio  = Number(fillers?.ratio)     || 0;

  const paceColor   = pace === "Ideal" ? "#4ecca3" : pace === "Too Fast" ? "#fc6c8f" : "#ffd166";
  const fillerColor = totalFillers === 0 ? "#4ecca3" : totalFillers <= 5 ? "#ffd166" : "#fc6c8f";
  const hasFillers  = (fillers?.breakdown || []).length > 0;
  const hasReps     = repetition.length > 0;
  const hasPron     = lowConfidenceWords.length > 0;

  return (
    <div className="results-page">
      <nav className="navbar">
        <span className="navbar-logo" onClick={() => navigate("landing")}>CLARIO</span>
        <div className="navbar-links">
          <button className="btn btn-ghost" onClick={() => navigate("dashboard")}>📊 Dashboard</button>
          <button className="btn btn-primary" onClick={() => navigate("practice")}>🎙️ Practice Again</button>
        </div>
      </nav>

      <div className="results-inner">

        {/* Header */}
        <div className="results-header">
          <span className="tag tag-purple">{scenario}</span>
          <h1>Your Results</h1>
          <p className="results-date">
            {new Date().toLocaleDateString("en-PH", { month: "long", day: "numeric", year: "numeric" })}
          </p>
        </div>

        {/* Dev debug panel */}
        <DebugPanel results={results} />

        {/* ① Transcript */}
        <div className="card transcript-section">
          <div className="transcript-header-row">
            <span className="transcript-title">📝 Your Transcript</span>
            <div className="transcript-legend">
              {hasFillers && <span><mark className="legend-mark filler-legend">filler word</mark></span>}
              {hasPron    && <span><mark className="legend-mark pronunciation-legend">unclear word</mark></span>}
            </div>
          </div>
          <div className="transcript-body-open">
            <HighlightedTranscript
              transcript={transcript}
              fillerBreakdown={fillers?.breakdown}
              lowConfidenceWords={lowConfidenceWords}
            />
          </div>
        </div>

        {/* ② Score overview */}
        <div className="score-row">
          <ScoreRing score={overall} />
          <div className="score-bars">
            <ScoreBar label="Pronunciation" value={scores?.pronunciation ?? 0} />
            <ScoreBar label="Speech Pace"   value={scores?.pace          ?? 0} />
            <ScoreBar label="Filler Words"  value={scores?.fillers       ?? 0} />
            <ScoreBar label="Flow"          value={scores?.flow          ?? 0} />
          </div>
        </div>

        {/* ③ Metrics row */}
        <div className="metrics-row">
          <MetricCard label="Words"       value={wordCount}    unit="total"   color="#a99dff" />
          <MetricCard label="Speech Rate" value={wpm}          unit="WPM"     color={paceColor}   note={pace} />
          <MetricCard label="Fillers"     value={totalFillers} unit="words"   color={fillerColor} note={`${fillerRatio}% of speech`} />
          <MetricCard
            label="Clarity"
            value={avgConfidence}
            unit="%"
            color={avgConfidence >= 85 ? "#4ecca3" : avgConfidence >= 70 ? "#ffd166" : "#fc6c8f"}
            note="pronunciation"
          />
        </div>

        {/* ④ Filler breakdown */}
        {hasFillers && (
          <div className="card filler-section">
            <h3 className="section-h3">🔍 Filler Word Breakdown</h3>
            <div className="filler-chips">
              {[...(fillers?.breakdown || [])].sort((a, b) => b.count - a.count).map(({ word, count }) => (
                <div key={word} className="filler-chip">
                  <span className="filler-word">"{word}"</span>
                  <span className="filler-count">{count}×</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ⑤ Repeated phrases */}
        {hasReps && (
          <div className="card repetition-section">
            <h3 className="section-h3">🔁 Repeated Phrases</h3>
            <div className="repetition-chips">
              {repetition.map((r, i) => (
                <div key={i} className="repetition-chip">
                  <span className="rep-phrase">"{r.phrase}"</span>
                  <span className="rep-count">{r.count}×</span>
                </div>
              ))}
            </div>
            <p className="rep-advice">Try varying your language to keep your listener engaged.</p>
          </div>
        )}

        {/* ⑥ AI Coaching */}
        <div className="card feedback-card">
          <div className="feedback-header">
            <span className="feedback-icon">🤖</span>
            <div>
              <h3>AI Coaching Feedback</h3>
              <p className="feedback-sub">Personalized insights powered by AI</p>
            </div>
          </div>
          <div className="feedback-body">
            <FormattedFeedback feedback={feedback} />
          </div>
        </div>

        {/* ⑦ Pronunciation Coach */}
        <PronunciationCoach
          pronunciationTips={pronunciationTips}
          lowConfidenceWords={lowConfidenceWords}
          avgConfidence={avgConfidence}
        />

        {/* Actions */}
        <div className="results-actions">
          <button className="btn btn-primary" onClick={() => navigate("practice")}>🎙️ Practice Again</button>
          <button className="btn btn-outline" onClick={() => navigate("dashboard")}>📈 View Progress</button>
        </div>

      </div>
    </div>
  );
}
